const NavigationList = () =>
{
    return(
        <nav>
            <NavigationItem menuItem="Home"></NavigationItem>
            <NavigationItem menuItem="Players"></NavigationItem>
            <NavigationItem menuItem="Panthers"></NavigationItem>
            <NavigationItem menuItem="League"></NavigationItem>
        </nav>
    )
}

export default NavigationList;
